return c - '0';
}
return c - 'a' + 10;
}
vector<vector<int>>
count(string s) {
map<char, int>
charCount;
int index = 0, n =
s.size();
while (index < n) {
// u
匹配规则
if (s[index] == 'u' && index + 1 < n && s[index + 1] == 'u')
{
charCount['j']++;
index +=2;
} else if (s[index] == 't' && index + 1 < n && s[index + 1]
== 't') {
charCount['b']++;
index += 2;
} else {
charCount[s[index]]++;
index++;
}
}
vector<vector<int>> res;
for(auto &p :
charCount) {
res.push_back({getKeyNum(p.first), p.second});
}
//
自定义排序
sort(res.begin(),
res.end(), [](vector<int> &a, vector<int> &b) {
return a[1] > b[1];
});
return res;
}
